import api from '../app/client';

export interface AdminUserListItem {
  id: string;
  userType: 'Employee' | 'Intern' | 'IdentityOnly';
  // Profile fields — null for IdentityOnly users
  firstName: string | null;
  middleName: string | null;
  lastName: string | null;
  fullName: string | null;
  birthDate: string | null;
  joiningDate: string | null;
  leavingDate: string | null;
  pan: string | null;
  profilePictureUrl: string | null;
  profilePictureVersion: number | null;
  // Type discriminators
  employeeID: string | null;
  enrollmentId: string | null;
  // Identity fields
  email: string | null;
  phoneNumber: string | null;
  isActive: boolean;
  otpEnabled: boolean;
  // Security overlay
  lastLoginAt: string | null;
  passwordLastChangedAt: string | null;
  isLockedOut: boolean;
  lockoutEnd: string | null;
  otpIsLockedOut: boolean;
  otpLockoutEnd: string | null;
  activeSessionCount: number;
  roles: string[];
}

export interface AdminUsersPagination {
  pageIndex: number;
  pageSize: number;
  totalCount: number;
  totalPages: number;
  hasNextPage: boolean;
  hasPreviousPage: boolean;
  data: AdminUserListItem[];
}

export interface AdminUsersParams {
  pageIndex?: number;
  pageSize?: number;
  sort?: string;
  sortOrder?: 'Ascending' | 'Descending';
  search?: string;
  userType?: string;
  active?: boolean;
}


export const adminService = {
  getUsers: (params?: AdminUsersParams): Promise<AdminUsersPagination> =>
    api.get('/admin/users', { params }).then(r => r.data),

  getUserById: (userId: string): Promise<AdminUserListItem> =>
    api.get(`/admin/users/${userId}`).then(r => r.data),

  setUserRole: (userId: string, role: string) =>
    api.patch(`/admin/users/${userId}/role`, { role }).then(r => r.data),

  setUserActive: (userId: string, active: boolean) =>
    api.patch(`/admin/users/${userId}/active`, { active }).then(r => r.data),

  resetUserPassword: (userId: string, newPassword: string) =>
    api.post(`/admin/users/${userId}/reset-password`, { newPassword }).then(r => r.data),

  unlockUserAccount: (userId: string) =>
    api.patch(`/admin/users/${userId}/unlock`).then(r => r.data),

  resetUserOtpLockout: (userId: string) =>
    api.patch(`/admin/users/${userId}/reset-otp-lockout`).then(r => r.data),

  revokeUserDevice: (userId: string, deviceId: string) =>
    api.delete(`/admin/users/${userId}/devices/${deviceId}`).then(r => r.data),

  getAdminUserDevices: (userId: string) =>
    api.get(`/admin/users/${userId}/devices`).then(r => r.data),

  revokeAllUserDevices: (userId: string) =>
    api.post(`/admin/users/${userId}/devices/revoke-all`).then(r => r.data),

  hardDelete: (entityType: string, id: string) =>
    api.delete(`/admin/hard-delete/${entityType}/${id}`).then(r => r.data),

  getLogLevel: () =>
    api.get('/admin/log-level').then(r => r.data),

  setLogLevel: (level: string) =>
    api.patch('/admin/log-level', { level }).then(r => r.data),
};
